mapper.sql:
WHERE U.APT_CMPLEX_NO = #{searchVO.aptCmplexNo}


    AND B.BILL_YM = #{searchVO.billYm}



    AND B.PYMT_STTS_CD = #{searchVO.pymtSttsCd}



    AND U.DONG_NO = #{searchVO.dongNo}



    AND H.HO LIKE '%' || #{searchVO.ho} || '%'

mapper.select:
SELECT * FROM ( SELECT ROW_NUMBER() OVER ( ORDER BY B.BILL_YM DESC, U.DONG_NM ASC, H.HO ASC ) AS RN,
B.BILL_NO, B.HO_NO, B.BILL_YM, B.BILL_PBLANC_DT, B.BILL_TOT_AMT, B.DUE_DT, B.PYMT_STTS_CD, B.PYMT_DT, B.PYMT_AMT, B.LATE_FEE_RT, B.LATE_FEE_AMT,
U.APT_CMPLEX_NO, U.DONG_NO, U.DONG_NM, H.HO, U.DONG_NM || '동 ' || H.HO || '호' AS DISPLAY_DONG_HO,
C.CODE_NAME AS PYMT_STTS_NM, C.CODE_CONTENT AS PYMT_STTS_CONTENT
FROM BILL B JOIN APT_DETAIL H ON B.HO_NO = H.HO_NO JOIN APT_UNIT U ON H.DONG_NO = U.DONG_NO LEFT JOIN COMMON_CODE C ON C.GROUP_CODE_NO = 'PAY_ST' AND C.CODE_NO_CD = B.PYMT_STTS_CD AND C.USE_YN = 'Y'
) WHERE RN BETWEEN #{startRow} AND #{endRow}
